function stageRunTests() {
  const packageJson = JSON.parse(fs.readFileSync('package.json', 'utf-8'));

  if (!packageJson.scripts || !packageJson.scripts.test) {
    log('No test script defined in package.json, skipping tests', 'WARN');
    return;
  }

  // Install dev dependencies for testing
  const devInstall = execCommand('npm ci', { nodeEnv: 'development' });
  if (!devInstall.success) {
    log('Dev dependency install had issues, attempting tests anyway', 'WARN');
  }

  const testResult = execCommand('npm test', {
    nodeEnv: 'test',
    timeout: 600000, // 10 minute timeout for tests
  });

  if (!testResult.success) {
    throw new Error(`Tests failed:\n${testResult.error || testResult.output}`);
  }

  log('All tests passed');

  // Re-install production-only deps after testing
  execCommand('npm ci --omit=dev', { nodeEnv: 'production' });
}

// =============================================================================
// Stage: Build Application
// =============================================================================
function stageBuildApplication() {
  const packageJson = JSON.parse(fs.readFileSync('package.json', 'utf-8'));

  if (!packageJson.scripts || !packageJson.scripts.build) {
    log('No build script defined, skipping build stage', 'WARN');
    return;
  }

  // Clean previous build
  if (fs.existsSync(BUILD_DIR)) {
    fs.rmSync(BUILD_DIR, { recursive: true, force: true });
    log(`Cleaned previous build directory: ${BUILD_DIR}`);
  }

  const buildResult = execCommand('npm run build', { nodeEnv: 'production' });
  if (!buildResult.success) {
    throw new Error(`Build failed:\n${buildResult.error || buildResult.output}`);
  }

  if (!fs.existsSync(BUILD_DIR)) {
    log(`Build directory ${BUILD_DIR} not found after build — build may output elsewhere`, 'WARN');
  } else {
    log(`Build output in ${BUILD_DIR}`);
  }
}

// =============================================================================
// Stage: Generate Build Artifact Checksums
// =============================================================================
function stageGenerateChecksums() {
  if (!fs.existsSync(ARTIFACT_DIR)) {
    fs.mkdirSync(ARTIFACT_DIR, { recursive: true });
  }

  const checksums = {};

  // Checksum the build directory if it exists
  if (fs.existsSync(BUILD_DIR)) {
    function hashDirectory(dir) {
      const entries = fs.readdirSync(dir, { withFileTypes: true });
      for (const entry of entries) {
        const fullPath = path.join(dir, entry.name);
        if (entry.isDirectory()) {
          hashDirectory(fullPath);
        } else if (entry.isFile()) {
          const content = fs.readFileSync(fullPath);
          const hash = crypto.createHash('sha256').update(content).digest('hex');
          checksums[path.relative('.', fullPath)] = hash;
        }
      }
    }
    hashDirectory(BUILD_DIR);
  }

  // Checksum key project files
  const keyFiles = ['package.json', 'package-lock.json', 'npm-shrinkwrap.json'];
  for (const file of keyFiles) {
    if (fs.existsSync(file)) {
      const content = fs.readFileSync(file);
      checksums[file] = crypto.createHash('sha256').update(content).digest('hex');
    }
  }

  pipelineState.checksums = checksums;

  // Write checksums manifest
  const manifestPath = path.join(ARTIFACT_DIR, 'checksums.json');
  fs.writeFileSync(manifestPath, JSON.stringify(checksums, null, 2));
  log(`Generated checksums for ${Object.keys(checksums).length} files`);

  // Copy SBOM to artifacts
  if (fs.existsSync(path.join(SBOM_DIR, 'sbom.json'))) {
    fs.copyFileSync(
      path.join(SBOM_DIR, 'sbom.json'),
      path.join(ARTIFACT_DIR, 'sbom.json')
    );
    fs.copyFileSync(
      path.join(SBOM_DIR, 'sbom.json.sha256'),
      path.join(ARTIFACT_DIR, 'sbom.json.sha256')
    );
    log('SBOM copied to artifacts directory');
  }

  // Write build manifest
  const buildManifest = {
    timestamp: new Date().toISOString(),
    nodeVersion: execCommand('node --version').output,
    npmVersion: execCommand('npm --version').output,
    deployTarget: DEPLOY_TARGET,
    gitCommit: execCommand('git rev-parse HEAD 2>/dev/null').output || 'unknown',
    gitBranch: execCommand('git rev-parse --abbrev-ref HEAD 2>/dev/null').output || 'unknown',
    sbomComponentCount: pipelineState.sbom ? pipelineState.sbom.components.length : 0,
    checksumCount: Object.keys(checksums).length,
  };
  fs.writeFileSync(
    path.join(ARTIFACT_DIR, 'build-manifest.json'),
    JSON.stringify(buildManifest, null, 2)
  );
  log('Build manifest generated');
}

// =============================================================================
// Stage: Deploy
// =============================================================================
function stageDeploy() {
  log(`Deploying to: ${DEPLOY_TARGET}`);

  // Verify SBOM exists before deploying
  const sbomPath = path.join(ARTIFACT_DIR, 'sbom.json');
  if (!fs.existsSync(sbomPath)) {
    throw new Error('SBOM not found in artifacts — refusing to deploy without SBOM');
  }

  // Verify SBOM integrity
  const sbomContent = fs.readFileSync(sbomPath);
  const actualChecksum = crypto.createHash('sha256').update(sbomContent).digest('hex');
  const expectedChecksumFile = path.join(ARTIFACT_DIR, 'sbom.json.sha256');
  if (fs.existsSync(expectedChecksumFile)) {
    const expectedChecksum = fs.readFileSync(expectedChecksumFile, 'utf-8').split(' ')[0].trim();
    if (actualChecksum !== expectedChecksum) {
      throw new Error('SBOM integrity check failed — checksum mismatch. Aborting deployment.');
    }
    log('SBOM integrity verified');
  }

  // Deployment strategy based on target
  switch (DEPLOY_TARGET) {
    case 'production': {
      log('Production deployment initiated');

      // In a real pipeline, this would call your deployment tool
      // Examples: AWS CodeDeploy, Kubernetes kubectl, Docker push, rsync, etc.
      const deployScript = 'scripts/deploy-production.sh';
      if (fs.existsSync(deployScript)) {
        const deployResult = execCommand(`bash ${deployScript}`, { timeout: 600000 });
        if (!deployResult.success) {
          throw new Error(`Production deployment failed: ${deployResult.error}`);
        }
      } else {
        log('No deploy script found at scripts/deploy-production.sh — simulating deployment', 'WARN');
        log('In production, configure DEPLOY_TARGET and provide deployment scripts');
      }
      break;
    }
    case 'staging': {
      log('Staging deployment initiated');
      const stagingScript = 'scripts/deploy-staging.sh';
      if (fs.existsSync(stagingScript)) {
        const result = execCommand(`bash ${stagingScript}`, { timeout: 600000 });
        if (!result.success) {
          throw new Error(`Staging deployment failed: ${result.error}`);
        }
      } else {
        log('No staging deploy script found — simulating', 'WARN');
      }
      break;
    }
    default:
      log(`Unknown deploy target: ${DEPLOY_TARGET}`, 'WARN');
  }

  log(`Deployment to ${DEPLOY_TARGET} completed`);
}

// =============================================================================
// Stage: Post-Deploy Verification
// =============================================================================
function stagePostDeployVerification() {
  const healthCheckUrl = process.env.HEALTH_CHECK_URL;
  if (!healthCheckUrl) {
    log('No HEALTH_CHECK_URL set, skipping post-deploy verification', 'WARN');
    return;
  }

  // Simple health check with retries
  let healthy = false;
  for (let attempt = 1; attempt <= 5; attempt++) {
    log(`Health check attempt ${attempt}/5: ${healthCheckUrl}`);
    const result = execCommand(`curl -sf -o /dev/null -w "%{http_code}" "${healthCheckUrl}" 2>/dev/null`);
    if (result.success && result.output === '200') {
      healthy = true;
      break;
    }
    // Wait before retry
    execCommand('sleep 5');
  }

  if (!healthy) {
    throw new Error('Post-deploy health check failed — consider rollback');
  }

  log('Post-deploy health check passed');
}

// =============================================================================
// Pipeline Execution
// =============================================================================
async function runPipeline() {
  log('=== CI/CD Pipeline Started ===');
  log(`Deploy target: ${DEPLOY_TARGET}`);
  log(`Working directory: ${process.cwd()}`);

  let exitCode = 0;

  try {
    runStage('Validate Environment', stageValidateEnvironment);
    runStage('Install Dependencies', stageInstallDependencies);
    runStage('Security Audit', stageSecurityAudit);
    runStage('Generate SBOM', stageGenerateSBOM);
    runStage('Validate SBOM', stageValidateSBOM);
    runStage('Run Tests', stageRunTests);
    runStage('Build Application', stageBuildApplication);
    runStage('Generate Checksums', stageGenerateChecksums);
    runStage('Deploy', stageDeploy);
    runStage('Post-Deploy Verification', stagePostDeployVerification);

    log('=== Pipeline completed SUCCESSFULLY ===');
  } catch (error) {
    log(`=== Pipeline FAILED: ${error.message} ===`, 'ERROR');
    exitCode = 1;
  }

  // Print summary
  const totalDuration = Date.now() - pipelineState.startTime;
  log('\n--- Pipeline Summary ---');
  for (const stage of pipelineState.stages) {
    const icon = stage.status === 'SUCCESS' ? '✓' : '✗';
    log(`  ${icon} ${stage.name}: ${stage.status} (${stage.duration}ms)`);
  }
  log(`Total duration: ${totalDuration}ms`);

  if (pipelineState.sbom) {
    log(`SBOM: ${pipelineState.sbom.components.length} components tracked`);
  }
  log(`Artifacts: ${ARTIFACT_DIR}`);
  log(`SBOM: ${SBOM_DIR}`);

  // Write final pipeline report
  const report = {
    status: exitCode === 0 ? 'SUCCESS' : 'FAILED',
    startTime: new Date(pipelineState.startTime).toISOString(),
    endTime: new Date().toISOString(),
    durationMs: totalDuration,
    deployTarget: DEPLOY_TARGET,
    stages: pipelineState.stages,
    sbomComponentCount: pipelineState.sbom ? pipelineState.sbom.components.length : 0,
    artifactChecksumCount: Object.keys(pipelineState.checksums).length,
  };

  if (!fs.existsSync(ARTIFACT_DIR)) {
    fs.mkdirSync(ARTIFACT_DIR, { recursive: true });
  }
  fs.writeFileSync(
    path.join(ARTIFACT_DIR, 'pipeline-report.json'),
    JSON.stringify(report, null, 2)
  );

  process.exit(exitCode);
}

runPipeline();